rules.exampleFix:
const failureOutput = `Update failed: ${error.message}`;
console.log(failureOutput);

const serialized = JSON.stringify(data, null, 2) + '\n';
fs.writeFileSync(path, serialized);

const isUnderLimit = actualBytes < 2700;
const sizeMessage = `Output is ${actualBytes} bytes`;
assert.ok(isUnderLimit, sizeMessage);

const isPatternAbsent = !actual.includes(pattern);
const leakMessage = `Pattern leaked: ${pattern}`;
assert.ok(isPatternAbsent, leakMessage);

const hasExpectedSubstring = actual.includes(expectedSubstring);
assert.ok(hasExpectedSubstring);

const hasExpectedInMessage = actual.error.message.includes(expectedInMessage);
assert.ok(hasExpectedInMessage);

